import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import './Navbar.css';

export default function Navbar() {
  const navigate = useNavigate();
  const { korisnik, odjava } = useAuth();

  return (
    <nav className="navbar">
      <div className="navbar-inner">
        <div className="navbar-logo" onClick={() => navigate('/')}>
          <span className="logo-symbol">∑</span>
          <span className="logo-text">Mate<em>TI</em>&amp;JA</span>
        </div>

        <div className="navbar-links">
          <NavLink to="/" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
            🏠 Početna
          </NavLink>
          <NavLink to="/casovi" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
            📚 Časovi
          </NavLink>
          <NavLink to="/zakazivanje" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
            📅 Zakaži čas
          </NavLink>
          <NavLink to="/moji-casovi" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
            ⭐ Moji časovi
          </NavLink>
          <NavLink to="/vezbanje" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
            🧮 Vežbanje
          </NavLink>
        </div>

        <div className="navbar-actions">
          {korisnik ? (
            <>
              <span className="user-greeting">
                Zdravo, <strong>{korisnik.ime}</strong>! 👋
              </span>
              <button className="navbar-btn logout-btn" onClick={() => {
                odjava();
                navigate('/');
              }}>
                Odjavi se
              </button>
            </>
          ) : (
            <>
              <button className="navbar-btn login-btn" onClick={() => navigate('/prijava')}>
                Prijavi se
              </button>
              <button className="navbar-btn register-btn" onClick={() => navigate('/registracija')}>
                Registruj se
              </button>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
